import React, { useState, useContext } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { ThemeContext } from '../context/ThemeContext';
import ThemeToggle from './ThemeToggle';
import { Cpu, LayoutDashboard, TrendingUp, LogOut, Terminal, Menu, X, Globe, Archive } from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useContext(AuthContext);
  const { isDarkMode } = useContext(ThemeContext); // Kept if you use it for conditional icons
  const navigate = useNavigate();
  const location = useLocation();
  const [mobileOpen, setMobileOpen] = useState(false);

  const isActive = (path) => location.pathname === path;

  return (
    <div style={{ position: 'sticky', top: 0, zIndex: 1000, padding: '1rem' }}>
      <nav style={{
        maxWidth: '1200px',
        margin: '0 auto',
        background: 'var(--surface-glass)',
        backdropFilter: 'blur(16px)',
        border: '1px solid var(--surface-border)',
        borderRadius: '16px',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: '0.6rem 1.2rem'
      }}>
        <Link to="/" style={{ display: 'flex', alignItems: 'center', gap: '10px', textDecoration: 'none', color: 'var(--text-primary)' }}>
          <Cpu size={20} color="var(--accent-primary)" />
          <span style={{ fontWeight: 800, fontSize: '0.9rem', letterSpacing: '0.1em' }}>FINIFY AI</span>
        </Link>

        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }} className="nav-desktop">
          {user ? (
            <>
              <Link to="/dashboard" className={isActive('/dashboard') ? 'active' : ''}>Dashboard</Link>
              <Link to="/generate" className={isActive('/generate') ? 'active' : ''}>Strategy</Link>
              <Link to="/live" className={isActive('/live') ? 'active' : ''}>Live</Link>
              <Link to="/vault" className={isActive('/vault') ? 'active' : ''}>Vault</Link>
              <ThemeToggle />
              <button onClick={() => logout()} style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer' }}><LogOut size={16}/></button>
            </>
          ) : (
            <>
              <Link to="/login">Access</Link>
              <Link to="/register" style={{ background: 'var(--accent-primary)', color: '#000', padding: '0.4rem 1rem', borderRadius: '8px', textDecoration: 'none', fontWeight: 700 }}>Initialize</Link>
              <ThemeToggle />
            </>
          )}
        </div>
      </nav>
    </div>
  );
};

export default Navbar;
